operation.add:
// ACIP: prepend hybrid-search product ids when enabled.
if ($this->config->get('module_acip_status')
    && $this->config->get('module_acip_replace_search')
    && !empty($this->request->get['search'])) {
    $this->registry->set('acip', new Acip($this->registry));
    $acip_results = $this->registry->get('acip')->search($this->request->get['search']);
    $acip_ids = array();
    foreach ($acip_results as $r) {
        if (!empty($r['product_id'])) { $acip_ids[] = (int)$r['product_id']; }
    }
    if ($acip_ids) { $this->request->get['acip_ids'] = $acip_ids; }
}
